multiply_bytes	.proc
	; -- multiply 2 bytes A and Y, result as byte in A  (signed or unsigned)
	; https://github.com/TobyLobster/multiply_test/blob/main/tests/mult29.a

_multiplicand    = P8ZP_SCRATCH_B1
_multiplier      = P8ZP_SCRATCH_REG

    sty  _multiplicand
    lsr  a
    sta  _multiplier
    lda  #0
    ldx  #2
-
    bcc  +
    clc
    adc  _multiplicand
+
    ror  a
    ror  _multiplier
    bcc  +
    clc
    adc  _multiplicand
+
    ror  a
    ror  _multiplier

    bcc  +
    clc
    adc  _multiplicand
+
    ror  a
    ror  _multiplier
    bcc  +
    clc
    adc  _multiplicand
+
    ror  a
    ror  _multiplier
    dex
    bne  -
    ; tay       ; if you want 16 bits result in AY, enable this again
    lda  _multiplier
    rts
		.pend


multiply_words	.proc
	; -- multiply two 16-bit words into a 32-bit result  (UNSIGNED)
	;      input: A/Y = first 16-bit number, multiply_words.multiplier = second 16-bit number
	;      output: multiply_words.result, 4-bytes/32-bits product, LSB order (low-to-high)  low 16 bits also in AY.
	;      you can retrieve the upper 16 bits via math.mul16_last_upper()

	; NOTE FOR NEGATIVE VALUES:
	;      The routine also works for NEGATIVE (signed) word values, but ONLY the lower 16 bits of the result are correct then!
	;      Prog8 only uses those so that's not an issue, but math.mul16_last_upper() no longer gives the correct result here.

; mult62.a
; from: https://github.com/TobyLobster/multiply_test/blob/main/tests/mult62.a
; based on Dr Jefyll, http://forum.6502.org/viewtopic.php?f=9&t=689&start=0#p19958
; - adjusted to use fixed zero page addresses
; - removed 'decrement to avoid clc' as this is slower on average
; - rearranged memory use to remove final memory copy and give LSB first order to result
; - removed temp zp storage bytes
; - unrolled the outer loop
; - unrolled the two inner loops once
;
; 16 bit x 16 bit unsigned multiply, 32 bit result
; Average cycles: ~442 ?
; 93 bytes

_multiplicand    = P8ZP_SCRATCH_W2   ; 2 bytes
multiplier      = result

; 16 bit x 16 bit unsigned multiply, 32 bit result
;
; On Entry:
;   (multiplier, multiplier+1): two byte multiplier, four bytes needed for result
;   (multiplicand, multiplicand+1): two byte multiplicand
; On Exit:
;   (result, result+1, result+2, result+3): product

    sta  _multiplicand
    sty  _multiplicand+1

    lda  #0              ;
    sta  result+2        ; 16 bits of zero in A, result+2
                        ;  Note:    First 8 shifts are  A -> result+2 -> result
                        ;           Final 8 shifts are  A -> result+2 -> result+1

    ; --- 1st byte ---
    ldy  #4              ; count for inner loop
    lsr  result

    ; inner loop (8 times)
_inner_loop
    ; first time
    bcc +
    tax                 ; retain A
    lda  result+2
    clc
    adc  _multiplicand
    sta  result+2
    txa                 ; recall A
    adc  _multiplicand+1

+
    ror  a                ; shift
    ror  result+2
    ror  result

    ; second time
    bcc +
    tax                 ; retain A
    lda  result+2
    clc
    adc  _multiplicand
    sta  result+2
    txa                 ; recall A
    adc  _multiplicand+1

+
    ror  a                 ; shift
    ror  result+2
    ror  result

    dey
    bne  _inner_loop      ; go back for 1 more shift?

    ; --- 2nd byte ---
    ldy  #4              ; count for inner loop
    lsr  result+1

    ; inner loop (8 times)
_inner_loop2
    ; first time
    bcc  +
    tax                 ; retain A
    lda  result+2
    clc
    adc  _multiplicand
    sta  result+2
    txa                 ; recall A
    adc  _multiplicand+1

+
    ror  a                ; shift
    ror  result+2
    ror  result+1

    ; second time
    bcc  +
    tax                 ; retain A
    lda  result+2
    clc
    adc  _multiplicand
    sta  result+2
    txa                 ; recall A
    adc  _multiplicand+1

+
    ror  a                ; shift
    ror  result+2
    ror  result+1
    dey
    bne  _inner_loop2     ; go back for 1 more shift?

    sta  result+3        ; ms byte of hi-word of result

    lda  result
    ldy  result+1
    rts

		.section BSS
result		.byte  ?,?,?,?       ; routine could be faster if this were in Zeropage...
		.send BSS
		.pend


multiply_longs  .proc
            ; 32-bit SIGNED multiplication.
            ; long1 in cx16.r12/r13, long2 in cx16.r14/r15, result in cx16.r14/r15
            ; clobbers R12+R13.

            lda  cx16.r13+1
            eor  cx16.r15+1
            sta  P8ZP_SCRATCH_B1       ; save sign info

            ; Negate l1 if negative
            lda  cx16.r13+1
            bpl  _l2_check
            jsr  _neg_r12r13

_l2_check
            ; Negate l2 if negative
            lda  cx16.r15+1
            bpl  _copy_mult
            jsr  _neg_r14r15

_copy_mult
            ; Copy multiplier to scratch (will be shifted)
            lda  cx16.r14
            sta  P8ZP_SCRATCH_W1
            lda  cx16.r14+1
            sta  P8ZP_SCRATCH_W1+1
            lda  cx16.r15
            sta  P8ZP_SCRATCH_W2
            lda  cx16.r15+1
            sta  P8ZP_SCRATCH_W2+1

            ; Clear result (R14R15 = 0)
            lda  #$00
            sta  cx16.r14
            sta  cx16.r14+1
            sta  cx16.r15
            sta  cx16.r15+1

            ldx  #32

_loop
            lda  P8ZP_SCRATCH_W1
            and  #1
            beq  _shift

            ; Add multiplicand to result
            clc
            lda  cx16.r14
            adc  cx16.r12
            sta  cx16.r14
            lda  cx16.r14+1
            adc  cx16.r12+1
            sta  cx16.r14+1
            lda  cx16.r15
            adc  cx16.r13
            sta  cx16.r15
            lda  cx16.r15+1
            adc  cx16.r13+1
            sta  cx16.r15+1

_shift
            ; Shift multiplicand left
            asl  cx16.r12
            rol  cx16.r12+1
            rol  cx16.r13
            rol  cx16.r13+1

            ; Shift multiplier right
            lsr  P8ZP_SCRATCH_W2+1
            ror  P8ZP_SCRATCH_W2
            ror  P8ZP_SCRATCH_W1+1
            ror  P8ZP_SCRATCH_W1

            dex
            bne  _loop

            ; Apply sign if needed
            lda  P8ZP_SCRATCH_B1
            bpl  _done
            jsr  _neg_r14r15

_done
            rts

            ; Subroutine: negate R12R13 in place
_neg_r12r13
            sec
            lda  #$00
            sbc  cx16.r12
            sta  cx16.r12
            lda  #$00
            sbc  cx16.r12+1
            sta  cx16.r12+1
            lda  #$00
            sbc  cx16.r13
            sta  cx16.r13
            lda  #$00
            sbc  cx16.r13+1
            sta  cx16.r13+1
            rts

            ; Subroutine: negate R14R15 in place
_neg_r14r15
            sec
            lda  #$00
            sbc  cx16.r14
            sta  cx16.r14
            lda  #$00
            sbc  cx16.r14+1
            sta  cx16.r14+1
            lda  #$00
            sbc  cx16.r15
            sta  cx16.r15
            lda  #$00
            sbc  cx16.r15+1
            sta  cx16.r15+1
            rts
		.pend

divmod_b_asm	.proc
	; signed byte division: make everything positive and fix sign afterwards
		sta  P8ZP_SCRATCH_B1
